     1→# nginx configuration for gifteddreamers.org
     2→# SPA routing - all routes serve index.html
     3→
     4→server {
     5→    listen 80;
     6→    server_name gifteddreamers.org www.gifteddreamers.org;
     7→
     8→    # Redirect HTTP to HTTPS
     9→    return 301 https://$server_name$request_uri;
    10→}
    11→
    12→server {
    13→    listen 443 ssl http2;
    14→    server_name gifteddreamers.org www.gifteddreamers.org;
    15→
    16→    # SSL certificates (adjust paths for your setup)
    17→    ssl_certificate /etc/letsencrypt/live/gifteddreamers.org/fullchain.pem;
    18→    ssl_certificate_key /etc/letsencrypt/live/gifteddreamers.org/privkey.pem;
    19→
    20→    # SSL settings
    21→    ssl_protocols TLSv1.2 TLSv1.3;
    22→    ssl_prefer_server_ciphers on;
    23→    ssl_ciphers ECDHE-ECDSA-AES128-GCM-SHA256:ECDHE-RSA-AES128-GCM-SHA256;
    24→
    25→    # Document root
    26→    root /home/admin/commoncloud/sites/gifteddreamers.org;
    27→    index index.html;
    28→
    29→    # Gzip compression
    30→    gzip on;
    31→    gzip_vary on;
    32→    gzip_min_length 1024;
    33→    gzip_types text/plain text/css text/xml text/javascript application/javascript application/json application/xml;
    34→
    35→    # Security headers
    36→    add_header X-Frame-Options "SAMEORIGIN" always;
    37→    add_header X-Content-Type-Options "nosniff" always;
    38→    add_header X-XSS-Protection "1; mode=block" always;
    39→    add_header Referrer-Policy "strict-origin-when-cross-origin" always;
    40→
    41→    # Cache static assets
    42→    location ~* \.(js|css|png|jpg|jpeg|gif|ico|svg|woff|woff2)$ {
    43→        expires 1y;
    44→        add_header Cache-Control "public, immutable";
    45→    }
    46→
    47→    # SPA routing - serve index.html for all routes
    48→    location / {
    49→        try_files $uri $uri/ /index.html;
    50→    }
    51→
    52→    # Deny access to hidden files
    53→    location ~ /\. {
    54→        deny all;
    55→    }
    56→}
    57→

