     1→import path from 'path';
     2→import { defineConfig } from 'vite';
     3→import react from '@vitejs/plugin-react';
     4→import type { Plugin } from 'vite';
     5→
     6→// Plugin to inject CSS preload links to break critical request chain
     7→// This allows CSS to download in parallel with HTML parsing, not sequentially
     8→function cssPreloadPlugin(): Plugin {
     9→  let cssFileName: string | null = null;
    10→  
    11→  return {
    12→    name: 'css-preload',
    13→    generateBundle(options, bundle) {
    14→      // Find CSS file in bundle during build
    15→      const cssFiles = Object.keys(bundle).filter((fileName) => 
    16→        fileName.endsWith('.css')
    17→      );
    18→      if (cssFiles.length > 0) {
    19→        const cssAsset = bundle[cssFiles[0]] as any;
    20→        cssFileName = cssAsset.fileName || cssFiles[0];
    21→      }
    22→    },
    23→    transformIndexHtml: {
    24→      order: 'post',
    25→      handler(html) {
    26→        // Add preload link for CSS BEFORE the stylesheet link
    27→        // Must match exact path format that Vite uses (absolute path with /)
    28→        // Include crossorigin to match Vite's stylesheet link
    29→        if (cssFileName) {
    30→          // Ensure absolute path (starts with /)
    31→          const href = cssFileName.startsWith('/') ? cssFileName : `/${cssFileName}`;
    32→          const preloadLink = `    <link rel="preload" as="style" href="${href}" crossorigin>`;
    33→          
    34→          // Find where Vite injects the stylesheet link and insert preload BEFORE it
    35→          // This ensures the preload is used immediately when stylesheet link is found
    36→          const stylesheetPattern = /<link[^>]*rel=["']stylesheet["'][^>]*href=["']([^"']*\/assets\/css\/[^"']*\.css)["'][^>]*>/i;
    37→          const match = html.match(stylesheetPattern);
    38→          
    39→          if (match) {
    40→            // Insert preload link right BEFORE the stylesheet link
    41→            return html.replace(match[0], `${preloadLink}\n${match[0]}`);
    42→          }
    43→          
    44→          // Fallback: insert before </head>
    45→          return html.replace('</head>', `${preloadLink}\n  </head>`);
    46→        }
    47→        return html;
    48→      },
    49→    },
    50→  };
    51→}
    52→
    53→export default defineConfig(({ mode }) => {
    54→    const isProduction = mode === 'production';
    55→    
    56→    return {
    57→      base: '/',
    58→      server: {
    59→        port: 3000,
    60→        host: '0.0.0.0',
    61→        allowedHosts: ['3000-icy05hrjm3itezj3j337a-94580408.sg1.manus.computer'],
    62→      },
    63→      plugins: [react(), cssPreloadPlugin()],
    64→      resolve: {
    65→        alias: {
    66→          '@': path.resolve(__dirname, '.'),
    67→        }
    68→      },
    69→      build: {
    70→        // Target modern browsers (ES2020+) to avoid legacy JavaScript
    71→        target: 'es2020',
    72→        // Enable minification
    73→        minify: 'terser',
    74→        terserOptions: {
    75→          compress: {
    76→            drop_console: isProduction, // Remove console.log in production
    77→            drop_debugger: isProduction,
    78→          },
    79→          format: {
    80→            // Remove comments and unnecessary whitespace
    81→            comments: false,
    82→          },
    83→        },
    84→        // Code splitting configuration
    85→        rollupOptions: {
    86→          output: {
    87→            manualChunks: (id) => {
    88→              // Separate vendor chunks for better caching
    89→              if (id.includes('node_modules')) {
    90→                if (id.includes('react') || id.includes('react-dom')) {
    91→                  return 'vendor-react';
    92→                }
    93→                if (id.includes('react-router')) {
    94→                  return 'vendor-router';
    95→                }
    96→                if (id.includes('lucide-react')) {
    97→                  return 'vendor-icons';
    98→                }
    99→                return 'vendor';
   100→              }
   101→            },
   102→            // Optimize chunk file names
   103→            chunkFileNames: 'assets/js/[name]-[hash].js',
   104→            entryFileNames: 'assets/js/[name]-[hash].js',
   105→            assetFileNames: 'assets/[ext]/[name]-[hash].[ext]',
   106→          },
   107→        },
   108→        // CSS code splitting - extract CSS into separate file
   109→        cssCodeSplit: true,
   110→        // Minify CSS
   111→        cssMinify: isProduction,
   112→        // Increase chunk size warning limit
   113→        chunkSizeWarningLimit: 1000,
   114→        // Disable source maps in production for smaller bundles
   115→        sourcemap: false,
   116→      },
   117→      // Optimize dependencies
   118→      optimizeDeps: {
   119→        include: ['react', 'react-dom', 'react-router-dom'],
   120→      },
   121→    };
   122→});
   123→

