     1→import React, { Suspense, lazy } from 'react';
     2→import { BrowserRouter as Router, Routes, Route, useLocation } from 'react-router-dom';
     3→import Navbar from './components/Navbar';
     4→import Footer from './components/Footer';
     5→import Breadcrumbs from './components/Breadcrumbs';
     6→import CookieConsent from './components/CookieConsent';
     7→import { trackPageView } from './lib/analytics';
     8→import { loadAnalytics, hasConsent } from './lib/analytics-loader';
     9→
    10→// Lazy load all pages for code splitting
    11→const Home = lazy(() => import('./pages/Home'));
    12→const Services = lazy(() => import('./pages/Services'));
    13→const Volunteer = lazy(() => import('./pages/Volunteer'));
    14→const Gruhp = lazy(() => import('./pages/Gruhp'));
    15→const Partners = lazy(() => import('./pages/Partners'));
    16→const CommonCloud = lazy(() => import('./pages/CommonCloud'));
    17→const About = lazy(() => import('./pages/About'));
    18→const MatchingGifts = lazy(() => import('./pages/MatchingGifts'));
    19→const FAQ = lazy(() => import('./pages/FAQ'));
    20→const Contact = lazy(() => import('./pages/Contact'));
    21→const Privacy = lazy(() => import('./pages/Privacy'));
    22→const Terms = lazy(() => import('./pages/Terms'));
    23→
    24→// Loading component
    25→const PageLoader = () => (
    26→  <div className="flex items-center justify-center min-h-[400px]">
    27→    <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary"></div>
    28→  </div>
    29→);
    30→
    31→// Page title mapping for analytics
    32→const pageTitles: Record<string, string> = {
    33→  '/': 'Home',
    34→  '/services': 'Services',
    35→  '/volunteer': 'Volunteer',
    36→  '/gruhp': 'GRUHP Fund',
    37→  '/corporate-partners': 'Corporate Partners',
    38→  '/common-cloud': 'Common Cloud',
    39→  '/about': 'About',
    40→  '/matching-gifts': 'Matching Gifts',
    41→  '/faq': 'FAQ',
    42→  '/contact': 'Contact',
    43→  '/privacy': 'Privacy Policy',
    44→  '/terms': 'Terms of Service',
    45→};
    46→
    47→const ScrollToTop = () => {
    48→  const { pathname } = useLocation();
    49→  React.useEffect(() => {
    50→    window.scrollTo(0, 0);
    51→    // Track page view for GA4
    52→    const pageTitle = pageTitles[pathname] || 'Gifted Dreamers';
    53→    trackPageView(pathname, pageTitle);
    54→  }, [pathname]);
    55→  return null;
    56→};
    57→
    58→const App: React.FC = () => {
    59→  // DO NOT load analytics automatically - wait for explicit user consent
    60→  // Analytics will only load when user clicks "Accept" in cookie banner
    61→  // This prevents third-party cookies from being set without consent
    62→  // Removed automatic loading to ensure privacy compliance
    63→  React.useEffect(() => {
    64→    // No automatic loading - wait for user to accept cookies
    65→  }, []);
    66→
    67→  return (
    68→    <Router future={{ v7_startTransition: true, v7_relativeSplatPath: true }}>
    69→      <ScrollToTop />
    70→      <div className="flex flex-col min-h-screen bg-white font-sans text-slate-900">
    71→        {/* Skip link for accessibility - hidden until focused */}
    72→        <a
    73→          href="#main-content"
    74→          className="sr-only focus:not-sr-only focus:absolute focus:top-4 focus:left-4 focus:z-50 focus:px-4 focus:py-2 focus:bg-primary focus:text-white focus:rounded-md focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary"
    75→        >
    76→          Skip to main content
    77→        </a>
    78→        <Navbar />
    79→        
    80→        {/* Conditional Breadcrumbs handled inside Breadcrumbs component via generic check, 
    81→            but for cleaner separation we can also conditionally render the component here.
    82→            The Breadcrumbs component implementation handles checking if path is home.
    83→        */}
    84→        <Breadcrumbs />
    85→
    86→        <main id="main-content" className="flex-grow">
    87→          <Suspense fallback={<PageLoader />}>
    88→            <Routes>
    89→              <Route path="/" element={<Home />} />
    90→              <Route path="/services" element={<Services />} />
    91→              <Route path="/volunteer" element={<Volunteer />} />
    92→              <Route path="/gruhp" element={<Gruhp />} />
    93→              <Route path="/corporate-partners" element={<Partners />} />
    94→              <Route path="/common-cloud" element={<CommonCloud />} />
    95→              
    96→              {/* Compliance & Footer Pages */}
    97→              <Route path="/about" element={<About />} />
    98→              <Route path="/matching-gifts" element={<MatchingGifts />} />
    99→              <Route path="/faq" element={<FAQ />} />
   100→              <Route path="/contact" element={<Contact />} />
   101→              <Route path="/privacy" element={<Privacy />} />
   102→              <Route path="/terms" element={<Terms />} />
   103→            </Routes>
   104→          </Suspense>
   105→        </main>
   106→        <Footer />
   107→        <CookieConsent 
   108→          onAccept={loadAnalytics}
   109→          onDecline={() => {
   110→            // User declined - analytics won't load
   111→            // This is handled by the analytics-loader not loading scripts
   112→          }}
   113→        />
   114→      </div>
   115→    </Router>
   116→  );
   117→};
   118→
   119→export default App;

