     1→import React, { useState, useEffect, useRef } from 'react';
     2→import { Link, useLocation } from 'react-router-dom';
     3→import { Menu, X, ArrowRight } from 'lucide-react';
     4→import Button from './Button';
     5→
     6→const Navbar: React.FC = () => {
     7→  const [isOpen, setIsOpen] = useState(false);
     8→  const location = useLocation();
     9→  const menuRef = useRef<HTMLDivElement>(null);
    10→
    11→  const navLinks = [
    12→    { label: 'Services', path: '/services' },
    13→    { label: 'Volunteer', path: '/volunteer' },
    14→    { label: 'GRUHP', path: '/gruhp' },
    15→    { label: 'Matching Gifts', path: '/matching-gifts' },
    16→    { label: 'Partners', path: '/corporate-partners' },
    17→    { label: 'Common Cloud', path: '/common-cloud' },
    18→  ];
    19→
    20→  const isActive = (path: string) => location.pathname === path;
    21→
    22→  // Close menu when clicking outside
    23→  useEffect(() => {
    24→    const handleClickOutside = (event: MouseEvent) => {
    25→      if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
    26→        setIsOpen(false);
    27→      }
    28→    };
    29→
    30→    if (isOpen) {
    31→      document.addEventListener('mousedown', handleClickOutside);
    32→    }
    33→
    34→    return () => {
    35→      document.removeEventListener('mousedown', handleClickOutside);
    36→    };
    37→  }, [isOpen]);
    38→
    39→  // Close menu on route change
    40→  useEffect(() => {
    41→    setIsOpen(false);
    42→  }, [location.pathname]);
    43→
    44→  return (
    45→    <nav className="sticky top-0 z-[100] bg-white/95 backdrop-blur-md border-b border-slate-200 shadow-sm">
    46→      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
    47→        <div className="flex justify-between h-20">
    48→          <div className="flex items-center">
    49→            <Link to="/" className="flex-shrink-0 flex items-center gap-3 group">
    50→              <img
    51→                src={`${import.meta.env.BASE_URL}images/logo.png`}
    52→                alt="Gifted Dreamers Logo"
    53→                width="40"
    54→                height="40"
    55→                className="w-10 h-10 object-contain transition-transform group-hover:scale-110"
    56→              />
    57→              <span className="text-xl font-bold tracking-tight"><span className="text-brand-red">Gifted</span> <span className="text-brand-blue">Dreamers</span></span>
    58→            </Link>
    59→          </div>
    60→
    61→          {/* Desktop Menu - Horizontal Links */}
    62→          <div className="hidden md:flex md:items-center md:space-x-1 lg:space-x-4">
    63→            {navLinks.map((link) => (
    64→              <Link
    65→                key={link.path}
    66→                to={link.path}
    67→                className={`px-3 py-2 rounded-md text-sm font-semibold transition-all ${
    68→                  isActive(link.path)
    69→                    ? 'text-primary bg-primary/5'
    70→                    : 'text-slate-600 hover:text-primary hover:bg-slate-50'
    71→                }`}
    72→              >
    73→                {link.label}
    74→              </Link>
    75→            ))}
    76→            <Link to="/contact" className="ml-2 lg:ml-4">
    77→              <Button variant="primary" size="sm" className="gap-2 font-bold">
    78→                Contact Us
    79→              </Button>
    80→            </Link>
    81→          </div>
    82→
    83→          {/* Hamburger Menu Button - Visible on all screens, functional on both mobile and desktop */}
    84→          <div className="flex items-center relative" ref={menuRef}>
    85→            <button
    86→              onClick={() => setIsOpen(!isOpen)}
    87→              className="inline-flex items-center justify-center p-2 rounded-md text-slate-500 hover:text-primary hover:bg-slate-100 focus:outline-none transition-colors"
    88→              aria-label="Toggle menu"
    89→              aria-expanded={isOpen}
    90→            >
    91→              {isOpen ? <X className="block h-6 w-6" /> : <Menu className="block h-6 w-6" />}
    92→            </button>
    93→
    94→            {/* Desktop Dropdown Menu */}
    95→            {isOpen && (
    96→              <div className="hidden md:block absolute top-full right-0 mt-2 w-56 bg-white rounded-lg shadow-lg border border-slate-200 py-2 z-50 animate-in fade-in slide-in-from-top-2 duration-200">
    97→                <div className="space-y-1">
    98→                  {navLinks.map((link) => (
    99→                    <Link
   100→                      key={link.path}
   101→                      to={link.path}
   102→                      onClick={() => setIsOpen(false)}
   103→                      className={`block px-4 py-3 text-sm font-semibold transition-colors ${
   104→                        isActive(link.path)
   105→                          ? 'text-primary bg-primary/5 border-l-4 border-primary'
   106→                          : 'text-slate-600 hover:text-primary hover:bg-slate-50'
   107→                      }`}
   108→                    >
   109→                      {link.label}
   110→                    </Link>
   111→                  ))}
   112→                  <div className="border-t border-slate-200 mt-2 pt-2 px-4">
   113→                    <Link to="/contact" onClick={() => setIsOpen(false)}>
   114→                      <Button variant="primary" size="sm" className="w-full justify-center gap-2 font-bold">
   115→                        Contact Us <ArrowRight className="h-4 w-4" />
   116→                      </Button>
   117→                    </Link>
   118→                  </div>
   119→                </div>
   120→              </div>
   121→            )}
   122→          </div>
   123→        </div>
   124→      </div>
   125→
   126→      {/* Mobile Full-Screen Menu */}
