     1→import React, { useEffect, useRef, useState } from 'react';
     2→
     3→interface RevealProps {
     4→  children: React.ReactNode;
     5→  delay?: number;
     6→  className?: string;
     7→  threshold?: number;
     8→}
     9→
    10→const Reveal: React.FC<RevealProps> = ({ 
    11→  children, 
    12→  delay = 0, 
    13→  className = "", 
    14→  threshold = 0.1 
    15→}) => {
    16→  const [isVisible, setIsVisible] = useState(false);
    17→  const domRef = useRef<HTMLDivElement>(null);
    18→
    19→  useEffect(() => {
    20→    const observer = new IntersectionObserver(
    21→      entries => {
    22→        entries.forEach(entry => {
    23→          if (entry.isIntersecting) {
    24→            setIsVisible(true);
    25→            observer.unobserve(entry.target);
    26→          }
    27→        });
    28→      },
    29→      { threshold }
    30→    );
    31→
    32→    const { current } = domRef;
    33→    if (current) {
    34→      observer.observe(current);
    35→    }
    36→
    37→    return () => {
    38→      if (current) observer.unobserve(current);
    39→    };
    40→  }, [threshold]);
    41→
    42→  return (
    43→    <div
    44→      ref={domRef}
    45→      className={`${isVisible ? 'reveal-visible' : 'reveal-hidden'} ${className}`}
    46→      style={{ transitionDelay: `${delay}ms` }}
    47→    >
    48→      {children}
    49→    </div>
    50→  );
    51→};
    52→
    53→export default Reveal;

