     1→/**
     2→ * Analytics Loader - Loads analytics scripts only after user consent
     3→ * Note: Givebutter and Double the Donation load immediately as they're required for widgets (not analytics)
     4→ */
     5→
     6→let analyticsLoaded = false;
     7→let consentGiven = false;
     8→
     9→/**
    10→ * Check if user has given consent for analytics
    11→ */
    12→export function hasConsent(): boolean {
    13→  if (typeof window === 'undefined') return false;
    14→  const consent = localStorage.getItem('cookie-consent');
    15→  return consent === 'accepted';
    16→}
    17→
    18→/**
    19→ * Load Google Analytics 4 (GA4)
    20→ */
    21→function loadGoogleAnalytics() {
    22→  if (analyticsLoaded) return;
    23→
    24→  // Load GA4 script
    25→  const script = document.createElement('script');
    26→  script.async = true;
    27→  script.src = 'https://www.googletagmanager.com/gtag/js?id=G-6X01DRJBC0';
    28→  document.head.appendChild(script);
    29→
    30→  // Initialize GA4
    31→  const win = window as any;
    32→  if (!win.dataLayer) {
    33→    win.dataLayer = [];
    34→  }
    35→  function gtag(...args: any[]) {
    36→    win.dataLayer.push(args);
    37→  }
    38→  win.gtag = gtag;
    39→  
    40→  gtag('js', new Date());
    41→  gtag('config', 'G-6X01DRJBC0');
    42→  gtag('config', 'GT-KD7JXRM8');
    43→  gtag('config', 'AW-17711415748');
    44→
    45→  analyticsLoaded = true;
    46→}
    47→
    48→/**
    49→ * Load Givebutter widgets
    50→ * IMPORTANT: This is NOT analytics - it's required for donation widgets functionality
    51→ * Loads immediately without consent requirement
    52→ */
    53→export function loadGivebutter() {
    54→  if (document.querySelector('script[src*="js.givebutter.com"]')) return;
    55→
    56→  const win = window as any;
    57→  if (!win.Givebutter) {
    58→    win.Givebutter = function(...args: any[]) {
    59→      if (!win.Givebutter.q) {
    60→        win.Givebutter.q = [];
    61→      }
    62→      win.Givebutter.q.push(args);
    63→    };
    64→  }
    65→  win.Givebutter('setOptions', { accountId: 'PWF9tXFflbTG12rU' });
    66→
    67→  const script1 = document.createElement('script');
    68→  script1.async = true;
    69→  script1.src = 'https://js.givebutter.com/elements/latest.js';
    70→  document.body.appendChild(script1);
    71→
    72→  const script2 = document.createElement('script');
    73→  script2.async = true;
    74→  script2.src = 'https://widgets.givebutter.com/latest.umd.cjs?acct=PWF9tXFflbTG12rU&p=other';
    75→  document.body.appendChild(script2);
    76→}
    77→
    78→/**
    79→ * Load Double the Donation widget
    80→ * IMPORTANT: This is NOT analytics - it's required for matching gifts plugin functionality
    81→ * Loads immediately without consent requirement
    82→ */
    83→export function loadDoubleDonation() {
    84→  if (document.querySelector('script[src*="doublethedonation.com"]')) return;
    85→
    86→  (window as any).DDCONF = { API_KEY: '6HMm5sEaYqgnLZmU' };
    87→  const script = document.createElement('script');
    88→  script.src = 'https://doublethedonation.com/api/js/ddplugin.js';
    89→  script.async = true;
    90→  document.body.appendChild(script);
    91→}
    92→
    93→/**
    94→ * Load all analytics scripts
    95→ * IMPORTANT: Only call this after user has explicitly consented
    96→ * Note: Givebutter and Double the Donation are NOT included here - they load immediately as they're required for widgets
    97→ */
    98→export function loadAnalytics() {
    99→  // Double-check consent before loading
   100→  if (!hasConsent()) {
   101→    console.warn('Analytics load attempted without consent - blocking');
   102→    return;
   103→  }
   104→
   105→  if (consentGiven) return;
   106→  consentGiven = true;
   107→
   108→  loadGoogleAnalytics();
   109→  // Givebutter and Double the Donation load immediately (not analytics - required for widgets)
   110→}
   111→
   112→/**
   113→ * Load analytics after user interaction (scroll, click, touch)
   114→ * ONLY if user has given consent - prevents third-party cookies without consent
   115→ */
   116→export function loadAnalyticsOnInteraction() {
   117→  // Only load if consent was given - don't load automatically
   118→  if (!hasConsent()) {
   119→    return;
   120→  }
   121→
   122→  if (consentGiven) {
   123→    loadAnalytics();
   124→    return;
   125→  }
   126→
   127→  // Load after user interaction (only if consent given)
   128→  let interacted = false;
   129→  const loadOnInteraction = () => {
   130→    if (!interacted && hasConsent()) {
   131→      interacted = true;
   132→      loadAnalytics();
   133→      // Remove listeners after first interaction
   134→      window.removeEventListener('scroll', loadOnInteraction, { capture: true } as any);
   135→      window.removeEventListener('click', loadOnInteraction, { capture: true } as any);
   136→      window.removeEventListener('touchstart', loadOnInteraction, { capture: true } as any);
   137→    }
   138→  };
   139→
   140→  window.addEventListener('scroll', loadOnInteraction, { once: true, passive: true, capture: true });
   141→  window.addEventListener('click', loadOnInteraction, { once: true, capture: true });
   142→  window.addEventListener('touchstart', loadOnInteraction, { once: true, passive: true, capture: true });
   143→}
