     1→/**
     2→ * Google Analytics Event Tracking Utilities
     3→ *
     4→ * This module provides helper functions for tracking conversion events
     5→ * in Google Analytics 4 (GA4) for Google Ad Grants compliance.
     6→ */
     7→
     8→// Extend the Window interface to include gtag
     9→declare global {
    10→  interface Window {
    11→    gtag?: (
    12→      command: 'event' | 'config' | 'set',
    13→      eventName: string,
    14→      params?: Record<string, unknown>
    15→    ) => void;
    16→  }
    17→}
    18→
    19→// Only log in development mode
    20→const isDev = import.meta.env?.DEV ?? false;
    21→const log = (message: string, ...args: unknown[]) => {
    22→  if (isDev) {
    23→    console.log(message, ...args);
    24→  }
    25→};
    26→
    27→/**
    28→ * Track a contact form submission (primary conversion)
    29→ * @param formType - Type of form submitted (contact, booking, etc.)
    30→ * @param organization - Organization name if provided
    31→ */
    32→export function trackFormSubmission(formType: string = 'contact', organization?: string) {
    33→  if (typeof window !== 'undefined' && window.gtag) {
    34→    window.gtag('event', 'generate_lead', {
    35→      event_category: 'Conversion',
    36→      event_label: formType,
    37→      value: 1,
    38→      organization: organization || 'not_provided',
    39→    });
    40→
    41→    log(`[Analytics] Form submission tracked: ${formType}`);
    42→  }
    43→}
    44→
    45→/**
    46→ * Track a donation button click event
    47→ * @param amount - The donation amount selected
    48→ * @param location - Where the button was clicked (e.g., 'hero', 'footer', 'gruhp')
    49→ */
    50→export function trackDonationClick(amount: number, location: string = 'unknown') {
    51→  if (typeof window !== 'undefined' && window.gtag) {
    52→    window.gtag('event', 'donate_click', {
    53→      event_category: 'Conversion',
    54→      event_label: location,
    55→      value: amount,
    56→      currency: 'USD',
    57→    });
    58→
    59→    log(`[Analytics] Donation click tracked: $${amount} from ${location}`);
    60→  }
    61→}
    62→
    63→/**
    64→ * Track a volunteer form submission
    65→ * @param skills - Array of selected skills
    66→ */
    67→export function trackVolunteerSubmission(skills: string[]) {
    68→  if (typeof window !== 'undefined' && window.gtag) {
    69→    window.gtag('event', 'volunteer_signup', {
    70→      event_category: 'Conversion',
    71→      event_label: skills.join(', '),
    72→      value: 1,
    73→    });
    74→
    75→    log(`[Analytics] Volunteer signup tracked: ${skills.join(', ')}`);
    76→  }
    77→}
    78→
    79→/**
    80→ * Track outbound link clicks (e.g., to Substack, Givebutter)
    81→ * @param url - The destination URL
    82→ * @param label - A descriptive label for the link
    83→ */
    84→export function trackOutboundLink(url: string, label: string = 'unknown') {
    85→  if (typeof window !== 'undefined' && window.gtag) {
    86→    window.gtag('event', 'click', {
    87→      event_category: 'Outbound Link',
    88→      event_label: label,
    89→      transport_type: 'beacon',
    90→      link_url: url,
    91→    });
    92→
    93→    log(`[Analytics] Outbound link tracked: ${url} (${label}`);
    94→  }
    95→}
    96→
    97→/**
    98→ * Track page views (for SPA navigation)
    99→ * @param pagePath - The page path
   100→ * @param pageTitle - The page title
   101→ */
   102→export function trackPageView(pagePath: string, pageTitle: string) {
   103→  if (typeof window !== 'undefined' && window.gtag) {
   104→    window.gtag('event', 'page_view', {
   105→      page_path: pagePath,
   106→      page_title: pageTitle,
   107→    });
   108→
   109→    log(`[Analytics] Page view tracked: ${pagePath}`);
   110→  }
   111→}
   112→
   113→/**
   114→ * Track section views (for scroll-based engagement)
