   116→ */
   117→export function trackSectionView(sectionName: string) {
   118→  if (typeof window !== 'undefined' && window.gtag) {
   119→    window.gtag('event', 'section_view', {
   120→      event_category: 'Engagement',
   121→      event_label: sectionName,
   122→    });
   123→
   124→    log(`[Analytics] Section view tracked: ${sectionName}`);
   125→  }
   126→}
   127→
   128→/**
   129→ * Track service page interest (for Ad Grants keyword tracking)
   130→ * @param serviceName - Name of the service viewed
   131→ */
   132→export function trackServiceInterest(serviceName: string) {
   133→  if (typeof window !== 'undefined' && window.gtag) {
